// INGEST-03: Log raw payload for audit/debug
// NOTIF-04 prep: Store last lead in staticData for error recovery
const lead = $input.first().json;

// Log to n8n execution log (visible in Executions view for 7 days)
console.log('RAW_LEAD:', JSON.stringify(lead));

// Store in workflow static data so Error Handler workflow can recover it
// This survives even if subsequent nodes fail
const staticData = $getWorkflowStaticData('global');
staticData.lastLead = JSON.stringify(lead);
staticData.lastLeadTime = new Date().toISOString();

// Pass through unchanged — do not modify the payload
return $input.all();

// Parse Google Ads Lead Form nested array into flat fields
// Source: https://developers.google.com/google-ads/webhook/docs/implementation
const lead = $input.first().json;
const fields = {};

for (const col of lead.user_column_data || []) {
  fields[col.column_name] = col.string_value;
}

// is_test check: log-only mode, no sends for test leads
// Note: deduplication still runs for is_test leads — intentional
const isTest = lead.is_test === true;

return [{
  json: {
    lead_id: lead.lead_id,
    is_test: isTest,
    phone: fields['PHONE_NUMBER'] || null,
    email: fields['EMAIL'] || null,
    name: fields['FULL_NAME'] || 'Prospect',
    request: fields['demande'] || fields['message'] || fields['MESSAGE'] || '',
    submit_time: lead.lead_submit_time,
    raw: lead
  }
}];

// Parse Claude API response and prepare SMS fields
// RESP-01: extract generated message
const claudeOutput = $json.content?.[0]?.text || '';

// RESP-05: truncate to 155 chars to stay within single SMS segment (160 minus safety margin)
const claudeMessage = claudeOutput.length > 155
  ? claudeOutput.substring(0, 152) + '...'
  : claudeOutput;

// Carry forward all lead fields for downstream nodes
return [{
  json: {
    lead_id: $json.lead_id,
    is_test: $json.is_test,
    phone: $json.phone,
    email: $json.email,
    name: $json.name,
    request: $json.request,
    claude_message: claudeMessage,
    claude_raw: claudeOutput,
    submit_time: $json.submit_time,
    raw: $json.raw
  }
}];
